  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n  output   = \"../src/generated/client\"\n}\n\ndatasource db {\n  provider  = \"postgresql\"\n  url       = env(\"DATABASE_URL\")\n  directUrl = env(\"DIRECT_DATABASE_URL\")\n}\n\nmodel Tenant {\n  id                  String               @id @default(uuid())\n  slug                String               @unique // Used for /t/[slug] routing\n  name                String\n  createdAt           DateTime             @default(now())\n  updatedAt           DateTime             @updatedAt\n  products            Product[]\n  orders              Order[]\n  settings            TenantSettings?\n  demandScores        DemandScore[]\n  purchaseSuggestions PurchaseSuggestion[]\n}\n\nmodel TenantSettings {\n  id                  String   @id @default(uuid())\n  tenantId            String   @unique\n  tenant              Tenant   @relation(fields: [tenantId], references: [id])\n  brandName           String?\n  logoUrl             String?\n  primaryColor        String?\n  accentColor         String?\n  themeMode           String   @default(\"light\") // light, dark, system\n  glassOpacity        Float    @default(0.8)\n  blurIntensity       Float    @default(10.0)\n  domainCustom        String?  @unique\n  paymentSettingsJson Json? // Feature flags eg: { paymentModePix: \"MANUAL_LINK\", paymentModeCard: \"MANUAL_LINK\" }\n  createdAt           DateTime @default(now())\n  updatedAt           DateTime @updatedAt\n}\n\nmodel User {\n  id        String   @id @default(uuid())\n  email     String   @unique\n  name      String?\n  password  String\n  role      Role     @default(CUSTOMER)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nenum Role {\n  ADMIN\n  STAFF\n  SUPPORT\n  CUSTOMER\n}\n\nmodel Product {\n  id           String         @id @default(uuid())\n  tenantId     String\n  tenant       Tenant         @relation(fields: [tenantId], references: [id])\n  name         String\n  slug         String         @unique // Added slug for catalog routing\n  description  String?\n  price        Float\n  images       ProductImage[]\n  variants     Variant[]\n  createdAt    DateTime       @default(now())\n  updatedAt    DateTime       @updatedAt\n  demandScores DemandScore[]\n}\n\nmodel ProductImage {\n  id        String   @id @default(uuid())\n  url       String\n  productId String\n  product   Product  @relation(fields: [productId], references: [id])\n  createdAt DateTime @default(now())\n}\n\nmodel Variant {\n  id              String           @id @default(uuid())\n  productId       String\n  product         Product          @relation(fields: [productId], references: [id])\n  sku             String           @unique\n  name            String // e.g., \"M - Home\", \"L - Away\"\n  inventory       Inventory?\n  orderItems      OrderItem[]\n  supplierProduct SupplierProduct?\n  dropshipEnabled Boolean          @default(false)\n  createdAt       DateTime         @default(now())\n  updatedAt       DateTime         @updatedAt\n}\n\nmodel Inventory {\n  id        String   @id @default(uuid())\n  variantId String   @unique\n  variant   Variant  @relation(fields: [variantId], references: [id])\n  available Int      @default(0)\n  reserved  Int      @default(0)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel Supplier {\n  id               String            @id @default(uuid())\n  name             String\n  contactEmail     String?\n  supplierProducts SupplierProduct[]\n  createdAt        DateTime          @default(now())\n  updatedAt        DateTime          @updatedAt\n}\n\nmodel SupplierProduct {\n  id         String   @id @default(uuid())\n  supplierId String\n  supplier   Supplier @relation(fields: [supplierId], references: [id])\n  variantId  String   @unique // 1:1 for simplicity in MVP, could be 1:N\n  variant    Variant  @relation(fields: [variantId], references: [id])\n  costPrice  Float\n  leadTime   Int // Days to ship\n  createdAt  DateTime @default(now())\n  updatedAt  DateTime @updatedAt\n}\n\nmodel Order {\n  id                      String      @id @default(uuid())\n  tenantId                String\n  tenant                  Tenant      @relation(fields: [tenantId], references: [id])\n  userId                  String? // Added for Phase 1\n  customerEmail           String\n  customerName            String\n  totalAmount             Float\n  status                  OrderStatus @default(REQUESTED_PAYMENT)\n  paymentLinkManualUrl    String? // Link Pix colado pelo admin (Fase 1)\n  paymentMethodPreference String? // e.g., \"PIX_MANUAL\"\n  paidAt                  DateTime?\n  orderItems              OrderItem[]\n  createdAt               DateTime    @default(now())\n  updatedAt               DateTime    @updatedAt\n}\n\nmodel OrderItem {\n  id              String          @id @default(uuid())\n  orderId         String\n  order           Order           @relation(fields: [orderId], references: [id])\n  variantId       String\n  variant         Variant         @relation(fields: [variantId], references: [id])\n  quantity        Int\n  price           Float // Price at time of purchase\n  fulfillmentType FulfillmentType @default(STOCK)\n  createdAt       DateTime        @default(now())\n  updatedAt       DateTime        @updatedAt\n}\n\nenum OrderStatus {\n  REQUESTED_PAYMENT\n  LINK_SENT\n  PAID\n  PROCESSING\n  SHIPPED\n  DELIVERED\n  CANCELED\n}\n\nenum FulfillmentType {\n  STOCK\n  DROPSHIP\n  ON_DEMAND\n}\n\nmodel DemandScore {\n  id        String   @id @default(uuid())\n  tenantId  String\n  tenant    Tenant   @relation(fields: [tenantId], references: [id])\n  productId String\n  product   Product  @relation(fields: [productId], references: [id])\n  score     Float    @default(0)\n  period    String // e.g., \"7d\", \"14d\", \"30d\"\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([tenantId, productId, period])\n}\n\nmodel PurchaseSuggestion {\n  id           String   @id @default(uuid())\n  tenantId     String\n  tenant       Tenant   @relation(fields: [tenantId], references: [id])\n  variantSku   String // Linked to Variant by SKU for loose coupling or directly\n  suggestedQty Int\n  reason       String?\n  createdAt    DateTime @default(now())\n}\n",
